fixed_code:
fn print_slice<'a>(s: &'a str, slice: &'a [char]) {
    if !slice.is_empty() {
        println!("{}", &slice[0]);
    } else {
        println!("Slice is empty");
    }
}

fn main() {
    let s = "hello world";
    let slice = s.chars().collect::<Vec<_>>();
    print_slice(s, &slice);
}

